-- Langar Bar V4.4.0 Breakfast Menu Update
-- Upserts the latest local app menu into Supabase.
-- It also deactivates old menu categories/items first so old breakfast/toast items do not remain visible.
begin;
update public.menu_items set active=false, available_in_menu=false, updated_at=now();
update public.menu_categories set active=false, updated_at=now();
commit;
